#include <stdio.h>

int min(int x, int y, int z) {
    int m = x;
    if (y < m) m = y;
    if (z < m) m = z;
    return m;
}

int min_two(int x, int y) {
    return x < y ? x : y;
}

int main() {
    int n, a, b, c;
    scanf("%d", &n);
    scanf("%d", &a);
    scanf("%d", &b);
    scanf("%d", &c);
    int l = min(a, b, c);
    if (n == 1) {
        printf("0\n");
    } else if (l != c) {
        printf("%d\n", (n-1)*l);
    } else {
        printf("%d\n", (n-2)*l + min_two(a, b));
    }
    return 0;
}
